import{_ as a,c as e,o as t,a8 as s}from"./chunks/framework.537aTjEo.js";const b=JSON.parse('{"title":"办公室双屏幕建议","description":"","frontmatter":{},"headers":[],"relativePath":"兴趣/办公室双屏幕建议.md","filePath":"兴趣/办公室双屏幕建议.md","lastUpdated":1717397989000}'),o={name:"兴趣/办公室双屏幕建议.md"},r=s('<h1 id="办公室双屏幕建议" tabindex="-1">办公室双屏幕建议 <a class="header-anchor" href="#办公室双屏幕建议" aria-label="Permalink to &quot;办公室双屏幕建议&quot;">​</a></h1><h2 id="方案选择" tabindex="-1">方案选择 <a class="header-anchor" href="#方案选择" aria-label="Permalink to &quot;方案选择&quot;">​</a></h2><p>如果是笔记本的话可以直接买一个type-c扩展坞，可以在笔记本原来的基础上扩展出另一个接口，但是这个接口有可能和原来笔记本上的接口不能同时使用，这个还是得看运气。实在不行只能外接一个屏幕加上笔记本本身的屏幕，组成双屏幕了。还有一种就是usb to xxx接口的转换器，之所以是推荐usb就是因为usb的通用性，这个转换器基本上可以同时用于笔记本和台式机。</p><p>台式机目前可选的有两种，一种是亮机卡另一种就是usb to xxx接口的转换器，目前看来不推荐亮机卡，因为亮机卡这个玩意是很老的，有可能有兼容问题。最好的选择还是转换器。</p><h2 id="转换器选择" tabindex="-1">转换器选择 <a class="header-anchor" href="#转换器选择" aria-label="Permalink to &quot;转换器选择&quot;">​</a></h2><p>转换器一般有typec 和usb两种，usb的有2.0和3.0，我建议选择usb，typec一般使用的视频传输协议，但是偏偏台式机一般不带雷电协议只能兼容采用特殊驱动的usb转换器。这里我就推荐usb转换器。还有一个就是看你的屏幕的用途，一般副屏如果不看视频玩游戏只是看看代码，2.0的也不是不能用。想要视频60hz还是需要买个3.0的比较好，3.0的价格通常比2.0的价格高2.5-6倍。</p><h2 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to &quot;注意事项&quot;">​</a></h2><p>我这里推荐usb的主要原因是usb可以同时用于笔记本和台式机，并且有比较高的性价比，并且满足副屏能用就行的要求。 usb转换器一般需要驱动支持，所以这个得看你的用途，如果你还想用在手机上，那一定要买typec的。 usb转换器不太稳定，追求稳定建议买一个typec的。</p>',8),_=[r];function c(n,i,d,h,l,u){return t(),e("div",null,_)}const m=a(o,[["render",c]]);export{b as __pageData,m as default};
